# 小红书旅游推送 v3 - 带封面图版（cron直接调用版）
import requests, json, sys, os, time
from datetime import datetime

sys.stdout.reconfigure(encoding='utf-8')
MCP_URL = 'http://localhost:18060/mcp'
UPLOAD_DIR = r'C:\Users\linkang\.openclaw\workspace\uploads'
os.makedirs(UPLOAD_DIR, exist_ok=True)

def init_mcp():
    s = requests.Session()
    hdrs = {'Accept': 'application/json, text/event-stream'}
    r1 = s.post(MCP_URL, json={
        'jsonrpc': '2.0', 'id': 1, 'method': 'initialize',
        'params': {'protocolVersion': '2024-11-05', 'capabilities': {},
                   'clientInfo': {'name': 'openclaw', 'version': '1.0'}}
    }, headers=hdrs, timeout=10)
    hdrs['Mcp-Session-Id'] = r1.headers.get('Mcp-Session-Id', '')
    s.post(MCP_URL, json={'jsonrpc': '2.0', 'method': 'notifications/initialized'}, headers=hdrs)
    return s, hdrs

def call_mcp(s, hdrs, tool_name, arguments):
    resp = s.post(MCP_URL, json={
        'jsonrpc': '2.0', 'id': 99, 'method': 'tools/call',
        'params': {'name': tool_name, 'arguments': arguments}
    }, headers=hdrs, timeout=30)
    return json.loads(resp.json()['result']['content'][0]['text'])

def get_travel_feeds(s, hdrs):
    raw = call_mcp(s, hdrs, 'list_feeds', {})
    feeds = raw.get('feeds', [])

    travel_kws = ['旅游', '旅行', '出游', '攻略', '打卡', '拍照', '度假', '景点', '风景', '春游', '踏青']
    results = []
    seen_ids = set()

    for f in feeds:
        if f.get('modelType') != 'note':
            continue
        note_id = f.get('id', '')
        if note_id in seen_ids:
            continue
        seen_ids.add(note_id)

        card = f.get('noteCard', {})
        title = card.get('displayTitle', '')
        if not any(kw in title for kw in travel_kws):
            continue

        cover = card.get('cover', {})
        img_url = cover.get('urlDefault', '') or cover.get('urlPre', '')
        interact = card.get('interactInfo', {})

        results.append({
            'title': title[:35],
            'likes': interact.get('likedCount', '0'),
            'collects': interact.get('collectedCount', '0'),
            'author': card.get('user', {}).get('nickname', ''),
            'note_id': note_id,
            'token': f.get('xsecToken', ''),
            'img_url': img_url,
            'type': card.get('type', 'normal'),
        })

        if len(results) >= 5:
            break

    # 如果旅游内容不够5条，补充其他内容
    if len(results) < 5:
        for f in feeds:
            if len(results) >= 5:
                break
            note_id = f.get('id', '')
            if note_id in seen_ids:
                continue
            seen_ids.add(note_id)

            card = f.get('noteCard', {})
            cover = card.get('cover', {})
            img_url = cover.get('urlDefault', '') or cover.get('urlPre', '')
            interact = card.get('interactInfo', {})
            results.append({
                'title': card.get('displayTitle', '')[:35],
                'likes': interact.get('likedCount', '0'),
                'collects': interact.get('collectedCount', '0'),
                'author': card.get('user', {}).get('nickname', ''),
                'note_id': note_id,
                'token': f.get('xsecToken', ''),
                'img_url': img_url,
                'type': card.get('type', 'normal'),
            })

    return results

def get_note_detail(s, hdrs, note_id, token):
    try:
        time.sleep(0.5)
        raw = call_mcp(s, hdrs, 'get_feed_detail', {
            'feed_id': note_id,
            'xsec_token': token,
            'load_all_comments': False,
            'limit': 1
        })
        note_data = raw.get('data', {}).get('note', {})
        desc = note_data.get('desc', '')[:80]
        images = note_data.get('imageList', [])
        detail_img = images[0].get('urlDefault', '') if images else ''
        return desc, detail_img
    except Exception as e:
        return "", ""

def download_img(s, url, path):
    try:
        if not url:
            return False
        r = s.get(url, timeout=15)
        if r.status_code == 200:
            with open(path, 'wb') as f:
                f.write(r.content)
            return True
    except:
        pass
    return False

def format_count(c):
    try:
        n = int(c)
        if n >= 10000:
            return f"{n//10000}万"
        return str(n)
    except:
        return c

if __name__ == "__main__":
    print("=== 小红书旅游推送开始 ===")
    s, hdrs = init_mcp()

    # 1. 获取Feeds
    results = get_travel_feeds(s, hdrs)
    print(f"获取Feeds: {len(results)}条")

    # 2. 获取详情和封面图
    for i, r in enumerate(results):
        summary, detail_img = get_note_detail(s, hdrs, r['note_id'], r['token'])
        r['summary'] = summary
        if detail_img:
            r['img_url'] = detail_img
        print(f"  [{i+1}] {r['title'][:20]} | 👍{r['likes']} | 图:{bool(r['img_url'])}")

    # 3. 下载封面图
    img_map = {}
    for i, r in enumerate(results):
        if r.get('img_url'):
            path = os.path.join(UPLOAD_DIR, f"push_{i+1}.jpg")
            ok = download_img(s, r['img_url'], path)
            if ok:
                img_map[i+1] = path
                print(f"  图片{i+1}下载: OK -> {path}")

    # 4. 构建消息（带图片）
    date = datetime.now().strftime("%Y-%m-%d")

    # 先发文字
    text_lines = [f"📊 小红书旅游热度Top5（{date}）\n"]
    for i, r in enumerate(results, 1):
        emoji = "🎬" if r['type'] == 'video' else "📝"
        text_lines.append(f"{emoji} {i}. {r['title']}")
        text_lines.append(f"   👍{format_count(r['likes'])} | ⭐{format_count(r['collects'])} | @{r['author']}")
        if r.get('summary'):
            text_lines.append(f"   📝 {r['summary']}")
        text_lines.append("")
    text_lines.append("---每日11:30自动推送")

    msg_text = '\n'.join(text_lines)
    print("\n消息内容:")
    print(msg_text)

    # 保存结果供飞书推送使用
    output = {
        'msg': msg_text,
        'images': img_map,  # {index: path}
        'results': results
    }
    output_path = os.path.join(UPLOAD_DIR, 'push_data.json')
    with open(output_path, 'w', encoding='utf-8') as f:
        json.dump(output, f, ensure_ascii=False, indent=2)
    print(f"\n数据已保存: {output_path}")
    print(f"共 {len(img_map)} 张图片")
    print("=== 完成 ===")

